+        // Maximum tags that fit: (block_size - HEADER_SIZE) / TAG_SIZE
+        let max_tags = (block_size - JBD2_HEADER_SIZE) / JBD2_TAG_SIZE;
+        let mut tags: Vec<(u32, u32)> = (0..max_tags)
+            .map(|i| {
