+                let flags = if i == max_tags - 1 {
+                    JBD2_TAG_FLAG_LAST
+                } else {
+                    0
+                };
+                (target, flags)
+            })
+            .collect();
+        // Ensure the last tag has LAST flag.
+        if let Some(last) = tags.last_mut() {
+            last.1 = JBD2_TAG_FLAG_LAST;
